+        let write_set_size = txn.pending_writes();
+        let read_set_size = txn.read_set().len();
+
+        debug!(
+            target: "ffs::mvcc",
+            txn_id = txn_id.0,
+            write_set_size,
+            read_set_size,
+            mode = "ssi",
+            "txn_commit_start"
+        );
+
+        let start = std::time::Instant::now();
+        let result = self.mvcc_store.write().commit_ssi(txn);
+        let duration_us = start.elapsed().as_micros() as u64;
+
+        match &result {
+            Ok(commit_seq) => {
+                info!(
+                    target: "ffs::mvcc",
+                    txn_id = txn_id.0,
+                    commit_seq = commit_seq.0,
+                    write_set_size,
+                    duration_us,
+                    mode = "ssi",
+                    "txn_commit_success"
+                );
+            }
+            Err(e) => {
+                warn!(
+                    target: "ffs::mvcc",
+                    txn_id = txn_id.0,
+                    error = %e,
